output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?captain ?captainLabel ?teamLabel WHERE {
  {
    wd:Q47774 wdt:P1137 ?captain .
    BIND("French national team" AS ?teamLabel)
  } UNION {
    wd:Q18741 wdt:P1137 ?captain .
    BIND("Tottenham Hotspur" AS ?teamLabel)
  }
  ?captain rdfs:label ?captainLabel .
  FILTER(lang(?captainLabel) = "en")
}

